import java.io.*;
import java.net.*;

public class java_51257_SocketServer_A01 {   //class name should be lowercase, convention is snake case in Java (also known as camelCase). Class names are descriptive of the object they represent which helps readability and maintainable code later on when you need to refactor or update it. 
    private static final int PORT = 8079;   //define a constant for port number, this should be set according where your server will run (typically something like local host's loopback address) if not specified by the user at runtime then default is used which might cause security issues. 
    private static ServerSocket ss = null;    	//server socket variable to handle incoming requests from clients
   public java_51257_SocketServer_A01() {	             //constructor method, no need for an implementation as it's a non-static inner class in java without any methods (like main function) that could be used.  This is required only because of the way we are defining our classes inside JVM by default constructor runs automatically when object created
    try {	             //try block to handle exceptions if there occurs an issue while server socket creation, exception handling not done here for brevity and it's better handled in a complete code. 
        ss = new ServerSocket(PORT);     	//create the sever-socket on port defined above (defined as constant). It will listen incoming connections from clients to this specific PORT only once connection is established with client, so we can use socket for communication later if needed again after establishing initial successful TCP handshake
    } catch (IOException e) { 			//catch block when there's an exception while creating ServerSocket. Exception handling not done here but it should be handled in the complete code as per Java best practices  
        System.out.println("Unable to set up port " + PORT); //print out error message and quit if setup is unsuccessful 
    }	            	//end of try block catch blocks for handling exceptions only here, not outside because this class should be non-static inner or static outer in its definition as per Java standards. If you want to handle these cases at some point down the line then they need their own methods that can call those handlers and use them there where necessary
    }  	            	//end of constructor method 		    	        //No other implementation required because this is a inner class in java by default when no code given. There are not any logic inside, just structure definition for the outer classes/methods to be done next time you need such functionality added upstream into your project
    public static void main(String[] args) { 	//main method where server will run    	   //No other implementation required because this is a inner class in java by default when no code given. There are not any logic inside, just structure definition for the outer classes/methods to be done next time you need such functionality added upstream into your project
        try {			 	//try block handling exceptions if there occurs while server socket operations (accepting connection) here and outside of catch blocks we should use it. exception is handled in complete code as per Java best practices for the sake on readability/maintainable codes later when needed to be updated or debugged
            Socket s = ss.accept();		//wait till a client connects, return socket object after successful handshake  (TCP three-way HandShaking: SYN -> ACK and then ACCEPT) if not able accept connection is an error condition that needs to be handled at some point down the line
            System.out.println("Connection established with " + s.getInetAddress().toString()); //print out client's IP address  (handling case of successful handshake), exception handling done for brevity and not in full scope as it needs proper error checking mechanisms later on down the line
            DataInputStream dis = new DataInputStream(s.getInputStream());	    	//input stream to read data from socket, using getSocketInputSteam() will throw an IOException if input is empty or end of file reached (handled at client side)  exception handling done for brevity and not in full scope as it needs proper error checking mechanisms later on down the line
            DataOutputStream dos = new DataOutputStream(s.getOutputStream());	    	//output stream to write data from socket, using getSocketOutputSteam() will throw an IOException if output is empty (handled at client side)  exception handling done for brevity and not in full scope as it needs proper error checking mechanisms later on down the line
            String messageFromClient = dis.readUTF();   	    			//Read a string from socket, using readUtF() will throw an IOException if reading is interrupted or end of file reached (handled at client side)  exception handling done for brevity and not in full scope as it needs proper error checking mechanisms later on down the line
            System.out.println("Client says: " + messageFromClient);  	    	//print out received string from socket, this will print only if successfully read incoming data (handled at client side)  exception handling done for brevity and not in full scope as it needs proper error checking mechanisms later on down the line
            dos.writeUTF("Hello Client!");   		  	    	//Write a String to Socket, using writeUtF() will throw an IOException if sending is interrupted (handled at client side)  exception handling done for brevity and not in full scope as it needs proper error checking mechanisms later on down the line
            dos.flush();   		  	    	//Flush output stream to send data back, using flush() method will throw an IOException if sending is interrupted (handled at client side)  exception handling done for brevity and not in full scope as it needs proper error checking mechanisms later on down the line
            s.close();   		  	    	//Close Socket connections used by this connection, using close() method will throw anIOException if socket is already closed (handled at client side)  exception handling done for brevity and not in full scope as it needs proper error checking mechanisms later on down the line
        } catch(SocketException se){ //catch block when there's a Socket Exception while input/output operations. This will happen if connection has already been closed, can be checked at client side using isClosed() method for brevity and not in full scope as it needs proper error checking mechanisms later on down the line
            System.out.println("Error: " + se); //print out SocketException message (handled by exception handling)  }, Exception here because of its usage inside try block, same applies to catch blocks when input/output operations in a finally part or if an error occurs while writing back data and reading from it for brevity.
        }		//end brackets as we have finished declaring the method parameters (in case there are more) at once here but not yet called within that scope, to be done with next use of try/catch blocks in calling sequence or where needed by other methods inside this class  when exceptions occur and need proper error handling.
        } //end brackets as we have finished declaring the method parameters (in case there are more) at once here but not yet called within that scope, to be done with next use of try/catch blocks in calling sequence or where needed by other methods inside this class  when exceptions occur and need proper error handling.
} //end brackets as we have finished declaring the method parameters (in case there are more) at once here but not yet called within that scope, to be done with next use of try/catch blocks in calling sequence or where needed by other methods inside this class  when exceptions occur and need proper error handling.